"use strict";const NEWTON_ITERATIONS=4,NEWTON_MIN_SLOPE=.001,SUBDIVISION_PRECISION=1e-7,SUBDIVISION_MAX_ITERATIONS=10,kSplineTableSize=11,kSampleStepSize=1/(kSplineTableSize-1),float32ArraySupported="function"==typeof Float32Array;function A(e,r){return 1-3*r+3*e}function B(e,r){return 3*r-6*e}function C(e){return 3*e}function calcBezier(e,r,t){return((A(r,t)*e+B(r,t))*e+C(r))*e}function getSlope(e,r,t){return 3*A(r,t)*e*e+2*B(r,t)*e+C(r)}function binarySubdivide(e,r,t,n,S){let i,a,l=0,o=r,u=t;for(;0<(i=calcBezier(a=o+(u-o)/2,n,S)-e)?u=a:o=a,Math.abs(i)>SUBDIVISION_PRECISION&&++l<SUBDIVISION_MAX_ITERATIONS;);return a}function newtonRaphsonIterate(r,e,t,n){let S=e;for(let e=0;e<NEWTON_ITERATIONS;++e){var i=getSlope(S,t,n);if(0===i)return S;var a=calcBezier(S,t,n)-r;S-=a/i}return S}export default function bezier(a,r,l,t){if(!(0<=a&&a<=1&&0<=l&&l<=1))throw new Error("bezier x values must be in [0, 1] range");const o=new(float32ArraySupported?Float32Array:Array)(kSplineTableSize);if(a!==r||l!==t)for(let e=0;e<kSplineTableSize;++e)o[e]=calcBezier(e*kSampleStepSize,a,l);return function(e){return a===r&&l===t?e:0===e?0:1===e?1:calcBezier(function(e){let r=0,t=1;for(var n=kSplineTableSize-1;t!==n&&o[t]<=e;++t)r+=kSampleStepSize;--t;var S=(e-o[t])/(o[t+1]-o[t]),i=getSlope(S=r+S*kSampleStepSize,a,l);return i>=NEWTON_MIN_SLOPE?newtonRaphsonIterate(e,S,a,l):0===i?S:binarySubdivide(e,r,r+kSampleStepSize,a,l)}(e),r,t)}}